INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('ppc_probe_points_readout_overlap', 'The 3 probe_points readout sprites ("E = 1200 V/m") collide horizontally into an unreadable run', 'MODERATE', 'peter_parker:renderer_primitives', 'pmCreateAutoLabel sizes its canvas to the MEASURED text width (floored at 384px). A full "E = 1200 V/m" string (~13 chars) measures far wider than the 384px floor, so at heightScale 0.34 the rendered glyph ink spans roughly 1.5+ world units — nearly double the 0.8-unit spacing between adjacent probe points. Three adjacent full-length readouts therefore visually run together ("E = 1200 V/E = 1200 V/E = 1200 V/m"). The A/B/C letter labels above the dots did NOT collide because a single glyph is short enough to stay under the 384px canvas floor, leaving mostly transparent padding either side (small visible ink relative to quad size).', 'When authoring N per-point live-readout sprites at a fixed spacing, keep each per-point sprite text SHORT enough that its measured ink width (not the padded/floored canvas quad) fits inside the spacing — a full "quantity = value unit" string rarely does at typical point spacing. Prefer: bare per-point NUMBER only + ONE shared quantity+unit legend built once (not per point), placed on its own row/band so it never shares a horizontal or vertical band with any per-point text regardless of how many digits the live value has.', 'manual', 'Read STATE_2__dense_t08000.png (or any frame at/after probe_points_at_ms + fade) directly: the 3 per-point readouts under A/B/C must render as 3 visually SEPARATE non-touching strings, all showing the IDENTICAL rounded number; the shared unit/quantity legend (if any) must not touch any per-point readout in any sampled frame.', 'FIXED', ARRAY['parallel_plate_capacitor_field'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-07-08_ppc_probe_points_followup_fixes', 'incident'),
('ppc_devstatemeta_missing_probe_points_at_ms', 'deriveStateMeta never registered probe_points_at_ms, so STATE_2 (probe_points variant) false-fails D7 and the frozen-frame capture photographs the state BEFORE the points appear', 'MAJOR', 'peter_parker:renderer_primitives', 'maxRevealForField3dState''s parallel_plates `capacitor` block registers gap_bracket_at_ms / field_lines_at_ms / probe_arrows_at_ms / sheet_fields_at_ms / cancel_outside_at_ms / fringe_at_ms / gap_widen as timed-reveal candidates that pin the capture window past each payoff — but the NEW probe_points_at_ms cue (added in the same renderer change that built the probe_points primitive) was never added to that candidate list. THE EYE therefore pinned STATE_2''s capture at the generic 1500ms default: the frozen frame photographed field-lines-only (before the t=5000ms probe_points reveal), and D7 saw the points fade in at t=5000-6000ms as unexpected LATE motion in a state it believed should already be fully revealed by 1500ms -> false "Animation died mid-state" fail. Same scar class as the already-fixed pp_devstatemeta_capacitor_block_registered_same_change (which registered the ORIGINAL capacitor block cues) — a new *_at_ms cue on an existing config block needs the same registration discipline as a brand-new scenario_type.', 'Any NEW *_at_ms (or other timed-reveal) field added to a scenario''s per-state config block MUST be registered in deriveStateMeta''s maxRevealForField3dState candidate list in the SAME change that adds the renderer-side ramp() for it — grep the sibling *_at_ms registrations for the same config block and add the new field alongside them (same `asNum(cap.X_at_ms, 0) + fadeMs + pad` pattern), not just alongside the existing scenario_type-registration rule (which only covers a scenario''s FIRST cue set, not every cue added afterward).', 'manual', 'npm run visual:eyes -- parallel_plate_capacitor_field: 26/26 deterministic checks pass (D7 no longer false-fails STATE_2). STATE_2__frozen.png read directly: shows the 3 A/B/C points + readouts (not an empty field-lines-only frame). A dense frame BEFORE probe_points_at_ms (e.g. t=4000ms when probe_points_at_ms=5000) shows the points NOT yet visible, confirming the reveal timing itself is unchanged — only the capture/classification window moved.', 'FIXED', ARRAY['parallel_plate_capacitor_field'], ARRAY['src/lib/validators/visual/deriveStateMeta.ts'], 'session_2026-07-08_ppc_probe_points_followup_fixes', 'incident')
